parameters.jsCode:
const targetMatch = $input.first().json.output.contentSnippet;
const searchItems = $('Check for Required Fields').all();
const regX = /(?<=[.!?])\s/;

return searchItems.filter(item => {
  const text = item.json.contentSnippet || "";
  // Extract first sentence: split by punctuation followed by space
  const firstSentence = text.split(regX)[0].trim();
  return targetMatch.includes(firstSentence);
});

